extension URLRequest {
    func logRequest(userID: String?) {
        guard let url = self.url else { return }
        
        NSLog("🌐 URLRequest - URL: %@", url.absoluteString)
        NSLog("Method: %@", httpMethod ?? "GET")
        
        if let headers = allHTTPHeaderFields {
            NSLog("Headers: %@", headers.description)
            print("Request headers: \(headers)")
        }
        
        if let body = httpBody, let bodyString = String(data: body, encoding: .utf8) {
            NSLog("Body: %@", bodyString)
            print("Request body: \(bodyString)")
        }
        
        if let uid = userID {
            NSLog("User ID: %@", uid)
            print("Request by user: \(uid)")
        }
    }
}

extension URLResponse {
    func logResponse(data: Data?, userID: String?) {
        guard let httpResponse = self as? HTTPURLResponse else { return }
        
        NSLog("📥 URLResponse - URL: %@", httpResponse.url?.absoluteString ?? "unknown")
        NSLog("Status Code: %d", httpResponse.statusCode)
        NSLog("Headers: %@", httpResponse.allHeaderFields.description)
        
        if let data = data, let responseString = String(data: data, encoding: .utf8) {
            NSLog("Response Data: %@", responseString)
            print("Response data: \(responseString)")
        }
        
        if let uid = userID {
            NSLog("User ID: %@", uid)
            print("Response for user: \(uid)")
        }
    }
}